              className="w-full bg-[#010a13]/80 border border-[#785a28] text-[#f0e6d2] px-4 py-3 pl-10 focus:outline-none focus:border-[#c8aa6e] focus:ring-1 focus:ring-[#c8aa6e] transition-colors font-bold placeholder-[#785a28]/50"
